import React, { useMemo } from 'react';
import { Typography } from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';
import { getFormattedDateForLanguage } from '../utils/gatsby-frontend-helpers';

// Components
import Link from './Link';

const useStyles = makeStyles((theme) => ({
    blogPostWrapper: {
        padding: '5px 0',
    },
    blogPostLink: {},
}));

const PostsList = ({
    className,
    posts,
    quantity,
    locale,
}) => {
    const classes = useStyles();

    let postsLoop = useMemo(() => posts.filter(
        ({ node }) => new Date().toISOString() >= node.frontmatter.date
    ), [posts]);

    if (quantity) {
        postsLoop = postsLoop.slice(0, quantity);
    }

    return (
        <div className={className}>
            {postsLoop.map(({ node }) => {
                const title = node.frontmatter.title || node.fields.slug;
                const showExcerpt = !node.frontmatter.hideExcerpt;

                return (
                    <article
                        key={node.fields.slug}
                        className={classes.blogPostWrapper}
                    >
                        <header>
                            <Typography
                                color="textPrimary"
                                variant="h5"
                            >
                                <Link
                                    className={classes.blogPostLink}
                                    color="textPrimary"
                                    to={node.fields.path}
                                >
                                    {title}
                                </Link>
                            </Typography>
                            <Typography
                                color="textSecondary"
                                variant="body2"
                                component="small"
                            >
                                {getFormattedDateForLanguage(node.frontmatter.date, locale)}
                            </Typography>
                        </header>
                        {showExcerpt && (
                            <section>
                                <em
                                    dangerouslySetInnerHTML={{ __html: node.excerpt }}
                                />
                            </section>
                        )}
                    </article>
                );
            })}
        </div>
    );
};

export default PostsList;
