import React, { useMemo } from 'react';
import { useIntl } from 'gatsby-plugin-intl';
import PropTypes from 'prop-types';
import { Typography } from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';

// Components
import Layout from '../components/Layout';
import SEO from '../components/SEO';

// Utils
import PostsList from '../components/PostsList';
import { capitalizeString } from '../utils/gatsby-frontend-helpers';

const useStyles = makeStyles((theme) => ({
    simplePostsListWrapper: {
        marginBottom: '10px',
    },
    tagText: {
        margin: '10px 0',
    },
    noPostsText: {
        marginBottom: '10px',
        padding: '0 5px',
    },
}));

const TagPageTemplate = ({ location, pageContext }) => {
    const { posts, title, ogImage } = pageContext;
    const intl = useIntl();
    const classes = useStyles();
    const pageTitle = useMemo(
        () => `${intl.formatMessage({ id: 'posts_tagged' })}"${capitalizeString(title)}"`,
        [intl, title]
    );

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={pageTitle}
                ogImage={ogImage}
                keywords={[
                    intl.formatMessage({ id: 'tags' }),
                ]}
            />
            <Typography
                className={classes.tagText}
                color="textPrimary"
                variant="h4"
            >
                {pageTitle}
            </Typography>
            {posts.length > 0 ?
                (
                    <PostsList
                        className={classes.simplePostsListWrapper}
                        posts={posts}
                        locale={intl.locale}
                    />
                )
                : (
                    <Typography
                        className={classes.noPostsText}
                        color="textPrimary"
                    >
                        {intl.formatMessage({ id: 'no_post_this_tag' })}
                    </Typography>
                )}
        </Layout>
    );
};

TagPageTemplate.propTypes = {
    pageContext: PropTypes.object.isRequired,
    location: PropTypes.object.isRequired,
};

export default TagPageTemplate;
